const OPENAI_RESPONSES_PROVIDER_SESSION_STATE_PREFIX = "openai-responses";

class OpenAIResponsesProviderSessionState implements ProviderSessionState {
	close(): void {}
}

function getOpenAIResponsesProviderSessionStateKey(model: Model<"openai-responses">): string {
	return `${OPENAI_RESPONSES_PROVIDER_SESSION_STATE_PREFIX}:${model.provider}`;
}

function canReplayOpenAIResponsesHistory(
	model: Model<"openai-responses">,
	providerSessionState: Map<string, ProviderSessionState> | undefined,
): boolean {
	if (!providerSessionState) return true;
	return providerSessionState.has(getOpenAIResponsesProviderSessionStateKey(model));
}

function markOpenAIResponsesProviderSessionActive(
	model: Model<"openai-responses">,
	providerSessionState: Map<string, ProviderSessionState> | undefined,
): void {
	if (!providerSessionState) return;
	const key = getOpenAIResponsesProviderSessionStateKey(model);
	if (!providerSessionState.has(key)) {
		providerSessionState.set(key, new OpenAIResponsesProviderSessionState());
	}
}

