				summary: options?.reasoningSummary || "auto",
			};
		} else if (model.name.startsWith("gpt-5")) {
			// Jesus Christ, see https://community.openai.com/t/need-reasoning-false-option-for-gpt-5/1351588/7
			messages.push({
				role: "developer",
